import React from 'react';
import { Link, useLocation } from 'react-router-dom';
import { useAuth } from '../context/AuthContext';

const Navbar: React.FC = () => {
  const { user, logout } = useAuth();
  const location = useLocation();

  const navStyle: React.CSSProperties = {
    background: 'linear-gradient(135deg, #2c3e50, #34495e)',
    padding: '0',
    boxShadow: '0 4px 20px rgba(0,0,0,0.1)',
    position: 'sticky',
    top: 0,
    zIndex: 1000
  };

  const navContainerStyle: React.CSSProperties = {
    display: 'flex',
    justifyContent: 'space-between',
    alignItems: 'center',
    maxWidth: '1400px',
    margin: '0 auto',
    padding: '0 20px'
  };

  const logoStyle: React.CSSProperties = {
    color: 'white',
    fontSize: '28px',
    fontWeight: '700',
    textDecoration: 'none',
    display: 'flex',
    alignItems: 'center',
    gap: '10px',
    padding: '15px 0'
  };

  const navLinksStyle: React.CSSProperties = {
    display: 'flex',
    listStyle: 'none',
    margin: 0,
    padding: 0,
    gap: '5px'
  };

  const linkStyle: React.CSSProperties = {
    color: 'rgba(255,255,255,0.9)',
    textDecoration: 'none',
    padding: '15px 16px',
    borderRadius: '8px',
    transition: 'all 0.3s ease',
    fontSize: '14px',
    fontWeight: '500',
    position: 'relative',
    overflow: 'hidden'
  };

  const activeLinkStyle: React.CSSProperties = {
    ...linkStyle,
    color: 'white',
    background: 'rgba(255,255,255,0.15)',
    backdropFilter: 'blur(10px)'
  };

  const userInfoStyle: React.CSSProperties = {
    display: 'flex',
    alignItems: 'center',
    gap: '15px',
    color: 'white'
  };

  const logoutBtnStyle: React.CSSProperties = {
    background: 'linear-gradient(135deg, #e74c3c, #c0392b)',
    border: 'none',
    color: 'white',
    padding: '10px 20px',
    borderRadius: '25px',
    cursor: 'pointer',
    fontSize: '14px',
    fontWeight: '500',
    transition: 'all 0.3s ease',
    boxShadow: '0 2px 10px rgba(231, 76, 60, 0.3)'
  };

  const isActive = (path: string) => location.pathname === path;

  return (
    <nav style={navStyle}>
      <div style={navContainerStyle}>
        <Link to="/" style={logoStyle}>
          <span style={{ fontSize: '32px' }}>🐷</span>
          <span>SGP</span>
        </Link>

        <ul style={navLinksStyle}>
          <li>
            <Link 
              to="/" 
              style={isActive('/') ? activeLinkStyle : linkStyle}
            >
              Dashboard
            </Link>
          </li>
          <li>
            <Link 
              to="/animals" 
              style={isActive('/animals') ? activeLinkStyle : linkStyle}
            >
              Animales
            </Link>
          </li>
          <li>
            <Link 
              to="/reproduction" 
              style={isActive('/reproduction') ? activeLinkStyle : linkStyle}
            >
              Reproducción
            </Link>
          </li>
          <li>
            <Link 
              to="/locations" 
              style={isActive('/locations') ? activeLinkStyle : linkStyle}
            >
              Ubicaciones
            </Link>
          </li>
          <li>
            <Link 
              to="/weights" 
              style={isActive('/weights') ? activeLinkStyle : linkStyle}
            >
              Pesajes
            </Link>
          </li>
          <li>
            <Link 
              to="/health" 
              style={isActive('/health') ? activeLinkStyle : linkStyle}
            >
              Sanidad
            </Link>
          </li>
          <li>
            <Link 
              to="/finance" 
              style={isActive('/finance') ? activeLinkStyle : linkStyle}
            >
              Finanzas
            </Link>
          </li>
          <li>
            <Link 
              to="/reports" 
              style={isActive('/reports') ? activeLinkStyle : linkStyle}
            >
              Reportes
            </Link>
          </li>
          <li>
            <Link 
              to="/analytics" 
              style={isActive('/analytics') ? activeLinkStyle : linkStyle}
            >
              IA
            </Link>
          </li>
        </ul>

        <div style={userInfoStyle}>
          <div style={{ display: 'flex', alignItems: 'center', gap: '10px', padding: '8px 16px', background: 'rgba(255,255,255,0.1)', borderRadius: '25px' }}>
            <span style={{ fontSize: '20px' }}>👤</span>
            <span style={{ fontSize: '14px', fontWeight: '500' }}>{user?.nombre}</span>
          </div>
          <button 
            onClick={logout}
            style={logoutBtnStyle}
            onMouseOver={(e) => {
              e.currentTarget.style.transform = 'translateY(-2px)';
              e.currentTarget.style.boxShadow = '0 4px 15px rgba(231, 76, 60, 0.4)';
            }}
            onMouseOut={(e) => {
              e.currentTarget.style.transform = 'translateY(0)';
              e.currentTarget.style.boxShadow = '0 2px 10px rgba(231, 76, 60, 0.3)';
            }}
          >
            Salir
          </button>
        </div>
      </div>
    </nav>
  );
};

export default Navbar;
